class Process:
 def __init__(self, arrival_time, burst_time):
 self.arrival_time = arrival_time
 self.burst_time = burst_time

def schedule_processes(processes):
 scheduled_processes = []
 current_time = 0
 ready_queue = []
 for process in processes:
 if process.arrival_time <= current_time:
 ready_queue.append(process)
 while ready_queue:
 process = ready_queue.pop(0)
 current_time += process.burst_time
 scheduled_processes.append(process)
 return scheduled_processes

# Example usage:
processes = [Process(0, 5), Process(2, 3), Process(4, 1)]
scheduled_processes = schedule_processes(processes)
for process in scheduled_processes:
 print(f'Process arrived at {process.arrival_time} and took {process.burst_time} units of time')

#include <stdio.h>
#include <stdlib.h>

typedef struct Process {
 int arrival_time;
 int burst_time;
} Process;

Process* schedule_processes(Process* processes, int n) {
 Process* scheduled_processes = (Process*)malloc(n * sizeof(Process));
 int current_time = 0;
 int ready_queue[n];
 int front = 0, rear = 0;
 for (int i = 0; i < n; i++) {
 if (processes[i].arrival_time <= current_time) {
 ready_queue[rear++] = i;
 }
 }
 while (front < rear) {
 int process_index = ready_queue[front++];
 current_time += processes[process_index].burst_time;
 scheduled_processes[process_index] = processes[process_index];
 }
 return scheduled_processes;
}

int main() {
 Process processes[] = {{0, 5}, {2, 3}, {4, 1}};
 int n = sizeof(processes) / sizeof(Process);
 Process* scheduled_processes = schedule_processes(processes, n);
 for (int i = 0; i < n; i++) {
 printf('Process arrived at %d and took %d units of time\n', scheduled_processes[i].arrival_time, scheduled_processes[i].burst_time);
 }
 return 0;
}
